import{_ as t,c as e,o as a,aR as l}from"./chunks/framework.C7RrxATG.js";const m=JSON.parse('{"title":"AI","description":"","frontmatter":{"version":"New"},"headers":[],"relativePath":"guide/ai.md","filePath":"guide/ai.md","lastUpdated":1776153999000}'),r={name:"guide/ai.md"},s=l('<h1 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h1><p>Wot UI 是一个 AI 友好型的组件库，本指南旨在介绍如何让 VSCode、Cursor、TRAE、Antigravity 等 AI 工具更好地理解 Wot UI 组件库。</p><h2 id="llms-txt" tabindex="-1">llms.txt <a class="header-anchor" href="#llms-txt" aria-label="Permalink to &quot;llms.txt&quot;">​</a></h2><p><a href="https://llmstxt.org/" target="_blank" rel="noreferrer">llms.txt</a> 是一个专为大型语言模型（Large Language Models，简称 LLMs）设计的文本文件，类似于 robots.txt，但目的不同。robots.txt 告诉搜索引擎爬虫哪些页面可以爬取，而 llms.txt 则是为 AI 工具提供网站内容的结构化信息，帮助 AI 更好地理解和索引网站内容。llms.txt 的名称中的 &quot;llms&quot; 代表 &quot;Large Language Models&quot;，表明这个文件是专门为大型语言模型设计的。它包含了项目的关键文档链接、代码示例和最佳实践，能够帮助 VSCode、Cursor、TRAE、Antigravity 等 AI 工具更好地理解 Wot UI 组件库。</p><h3 id="可用资源" tabindex="-1">可用资源 <a class="header-anchor" href="#可用资源" aria-label="Permalink to &quot;可用资源&quot;">​</a></h3><p>我们提供 2 个 llms.txt 路由来帮助 AI 工具访问文档：</p><ul><li><a href="https://wot-ui.cn/llms.txt" target="_blank" rel="noreferrer">llms.txt</a> - 包含所有组件及其文档链接的结构化概览</li><li><a href="https://wot-ui.cn/llms-full.txt" target="_blank" rel="noreferrer">llms-full.txt</a> - 提供包含实现细节和示例的完整文档</li></ul><h3 id="在-ai-工具中使用" tabindex="-1">在 AI 工具中使用 <a class="header-anchor" href="#在-ai-工具中使用" aria-label="Permalink to &quot;在 AI 工具中使用&quot;">​</a></h3><h4 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h4><p>在 Cursor 中找到 <code>Indexing &amp; Docs</code> 设置，并将 <code>llms.txt</code> 添加到 <code>Docs</code> 中，使用 <code>@Docs</code> 功能将 llms.txt 文件包含到您的项目中。</p><p><a href="https://cursor.com/docs/agent/tools/search" target="_blank" rel="noreferrer">详细了解 Cursor 中的 @Docs 功能</a></p><h4 id="trae" tabindex="-1">TRAE <a class="header-anchor" href="#trae" aria-label="Permalink to &quot;TRAE&quot;">​</a></h4><p>在 TRAE 中找到 <code>上下文/文档集</code> 设置，并将 <code>llms.txt</code> 添加到 <code>文档集</code> 中，使用 <code>#Docs</code> 功能将 llms.txt 文件包含到您的项目中。</p><p><a href="https://docs.trae.ai/ide/number-sign" target="_blank" rel="noreferrer">详细了解 TRAE 中的 #Docs 功能</a></p><h4 id="其他工具" tabindex="-1">其他工具 <a class="header-anchor" href="#其他工具" aria-label="Permalink to &quot;其他工具&quot;">​</a></h4><p>任何支持 <code>llms.txt</code> 标准或可以从 URL 摄取文档的工具都可以使用我们提供的 <code>llms.txt</code> 文件。你可以将 <code>llms.txt</code> 文件添加到你使用的工具的 <code>文档集</code>、<code>rules</code> 中，以帮助 AI 工具更好地理解 Wot UI 组件库。</p><h4 id="context7" tabindex="-1">context7 <a class="header-anchor" href="#context7" aria-label="Permalink to &quot;context7&quot;">​</a></h4><p>在不使用 <code>llms.txt</code> 的情况下，也可以使用 <a href="https://github.com/upstash/context7" target="_blank" rel="noreferrer">context7</a> 直接读取组件库文档。</p><p><a href="https://github.com/upstash/context7" target="_blank" rel="noreferrer">详细了解 context7</a></p><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p>Skills 是 AI 的&quot;超能力模板&quot;，是一套完整的、可复用的、能解决特定问题的方案，Wot UI 也提供了一些预定义的 <a href="https://skills.sh/?q=wot-ui" target="_blank" rel="noreferrer">Skills</a>，你可以直接在 AI 中使用。</p><h3 id="可用资源-1" tabindex="-1">可用资源 <a class="header-anchor" href="#可用资源-1" aria-label="Permalink to &quot;可用资源&quot;">​</a></h3><ul><li><a href="https://skills.sh/?q=wot-ui" target="_blank" rel="noreferrer">skills.sh</a> - 开放 Agent Skills 生态系统，收录了无数 skills，包含 Wot UI 相关的技能。</li><li><a href="https://starter.wot-ui.cn/guide/skills.html" target="_blank" rel="noreferrer">wot-starter</a> - Wot UI 提供的快速上手模板，包含 Wot UI 相关的技能。</li></ul><h3 id="在-ai-工具中使用-1" tabindex="-1">在 AI 工具中使用 <a class="header-anchor" href="#在-ai-工具中使用-1" aria-label="Permalink to &quot;在 AI 工具中使用&quot;">​</a></h3><p>推荐使用脚本安装 Skills，可以根据实际需求选择 Skills 的安装选项：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/wot-ui/wot-starter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wot-ui</span></span></code></pre></div><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://juejin.cn/post/7500981295105015847" target="_blank" rel="noreferrer">llms.txt：让 AI 更好地理解你的文档</a></li><li><a href="https://juejin.cn/post/7599268297201958950" target="_blank" rel="noreferrer">Agent Skills、Rules、Prompt、MCP，一文把它们理清楚了</a></li></ul>',28),o=[s];function i(h,n,c,d,u,p){return a(),e("div",null,o)}const x=t(r,[["render",i]]);export{m as __pageData,x as default};
